import sys
from bisect import bisect_left, bisect_right

input = sys.stdin.readline

def solve():
    n, m, k = map(int, input().split())
    xs = list(map(int, input().split()))
    ys = list(map(int, input().split()))
    xs_set = set(xs)
    ys_set = set(ys)

    # vert_gaps[gap_idx] = {x_coord: count}
    vert_gaps = {}
    # horiz_gaps[gap_idx] = {y_coord: count}
    horiz_gaps = {}

    for _ in range(k):
        xp, yp = map(int, input().split())
        on_vert = xp in xs_set
        on_horiz = yp in ys_set
        if on_vert and not on_horiz:
            # person is on vertical street only, find horizontal gap
            idx = bisect_right(ys, yp) - 1
            # yp is not in ys_set, so it's strictly between ys[idx] and ys[idx+1]
            if idx not in vert_gaps:
                vert_gaps[idx] = {}
            vert_gaps[idx][xp] = vert_gaps[idx].get(xp, 0) + 1
        elif on_horiz and not on_vert:
            # person is on horizontal street only, find vertical gap
            idx = bisect_right(xs, xp) - 1
            if idx not in horiz_gaps:
                horiz_gaps[idx] = {}
            horiz_gaps[idx][yp] = horiz_gaps[idx].get(yp, 0) + 1

    ans = 0
    for gap_dict in vert_gaps.values():
        total = sum(gap_dict.values())
        ans += total * (total - 1) // 2
        # subtract pairs on same vertical street (same x) - they are NOT inconvenient
        for c in gap_dict.values():
            ans -= c * (c - 1) // 2

    for gap_dict in horiz_gaps.values():
        total = sum(gap_dict.values())
        ans += total * (total - 1) // 2
        # subtract pairs on same horizontal street (same y) - they are NOT inconvenient
        for c in gap_dict.values():
            ans -= c * (c - 1) // 2

    print(ans)

t = int(input())
for _ in range(t):
    solve()

